  `office_location` varchar(255) NOT NULL,
  `round_img` varchar(255) NOT NULL,
  `entered_date` datetime NOT NULL,
  `departmentId` int DEFAULT NULL,
  `web_view_img` varchar(255) DEFAULT NULL,
  `mobile_view_img` varchar(255) DEFAULT NULL,
  `emp_carousel_img` varchar(255) DEFAULT NULL,
  `emp_carousel_hov_img` varchar(255) DEFAULT NULL,
  `emp_quote_img_one` varchar(255) DEFAULT NULL,
  `emp_quote_img_two` varchar(255) DEFAULT NULL,
  `designation` varchar(255) DEFAULT NULL,
  `message_img` varchar(255) DEFAULT NULL,
