INSERT INTO `employees` VALUES (5,'S.N.','本社営業部','resources/1735620014340-o8z0sdmc-Group_14724.png','2023-01-01 00:00:00',3,'resources/1737102891284-of679n5x-FV_01@2x.jpg','resources/1736047127838-jtwenjs8-1_again.png','resources/1735625212443-2vixg280-img_01@2x.png','resources/1735625254178-b7nh7kxi-img_01@2x.png','resources/1734685207813-v4xjdhu3-01.png','resources/1734685210931-t2kcqo9x-02.png','営業','resources/1735813323037-ph3uyx88-emplyee.png','就活生のあなたへメッセージ','これから沢山のことに挑戦したり、学びを得る機会があると思います。新しいことに積極的に取り組める環境は、自分の視野を広げる大きなチャンスです。ただ、様々な困難に遭遇することもあるかもしれません。そんな時は自分の興味や強みを最大限に活かせる場所を見つけてください。挑戦を恐れず、成長を楽しむ気持ちを持って、新たなステージに踏み出してみてください。これまでの経験が、みなさんのキャリアにとって貴重な一歩となることを願っています。','2024-12-19 10:17:35','2025-01-17 08:38:46','sales01','本社営業'),(6,'K.M.','本社制作部','resources/1735620001018-d3yef7zb-Group_15611.png','2019-01-01 00:00:00',7,'resources/1737102906976-ud2h5a45-FV_02@2x.jpg','resources/1734752934845-fh7pvhvd-img_01_mob.png','resources/1735625215195-ngyub22u-img_02@2x.png','resources/1735625256437-7n2sbuc2-img_02@2x.png','resources/1734684450292-550smcd9-01.png','resources/1734684454819-svvgkxsz-02.png','グラフィックデザイナー','resources/1734752931967-2o5tdhw7-img_06.png','就活生のあなたへメッセージ','GAは多岐にわたるクリエイティブを手掛けているため、新たなスキルや知識がどんどん身につき、確実に成長できる場所だと思います。また、部署や年齢に関わらず様々な社員の方々と接する機会があるため、デザインに関することだけではなく幅広く、沢山のことを経験・知識を吸収することができます。より良いものづくりを目指しながら、一緒に成長していきましょう。','2024-12-19 13:20:03','2025-01-17 08:38:08','graphic01','企画デザイングループ'),(7,'C.Y.','博多ソフトステーション','resources/1735620009456-mktujii7-1.png','2023-01-01 00:00:00',10,'resources/1737102910786-hifwc8ab-FV_03@2x.jpg','resources/1734754533010-b6ecna9a-img_01_mob.png','resources/1736760738595-c5pvp2lw-be_img_03@2x.png','resources/1736760671961-lsgouviw-af_img_03@2x.png','resources/1734684477077-661uj3hy-01.png','resources/1734684482476-xleufsts-02.png','Webデザイナー','resources/1734754529490-9c5yfqhn-img_06.png','就活生のあなたへメッセージ','就活は情報収集が一番大切だと思います。企業のWebサイトはその会社の顔と言えるものです。このサイトを含め、利用できるものは積極的に活用しましょう。例えば、OB・OG訪問をしたり、就職情報サイトを活用するのもいいですね。「自分がやりたいこと」が何かを振り返り、説明会にも積極的に参加して、自分に合う会社を見つけてください。新卒のチャンスを大切にして、自分が納得できる会社を選ぶことが大切です。気楽に臨んでください。応援しています！','2024-12-19 14:31:16','2025-01-17 08:37:36','web03','Webデザイングループ'),(8,'E.K.','関西市場開発部','resources/1735620016808-9ow595j3-Group_14741.png','2019-01-01 00:00:00',11,'resources/1737102914000-2iz4izqa-FV_04@2x.jpg','resources/1736047321589-0cv6ynms-4_mobb.png','resources/1735625222444-gxyd7ftz-img_04@2x.png','resources/1735625262017-d5q1rg1p-img_04@2x.png','resources/1734684496115-3zfc7wxv-01.png','resources/1734684500258-tq4vh1xy-02.png','映像ディレクター','resources/1734755056984-adyn1ken-img_06.png','就活生のあなたへメッセージ','就活は大変ですし、100%の努力をしても必ずしも理想の結果になるとは限りません。しかし諦めずに進めばきっといつか「自分のやりたいこと」にたどり着きます。私も元々志望していたカメラマンになれていませんが、映像ディレクターとして「やりたいこと」に関わることができています。\n今ある選択肢の中で、情熱を持って取り組めること、面白がれることを見つけて、それを「正解にしていく」努力ができればきっとどんな仕事でも楽しくなるはずです！気負わずありのまま勝負していってください！','2024-12-19 14:39:17','2025-01-17 08:37:01','movie01','映像デザイングループ'),(9,'Y.T.','関西市場開発部','resources/1735620005342-yhceypw4-Group_15607.png','2017-01-01 00:00:00',10,'resources/1737102917341-1bcxayd7-FV_05@2x.jpg','resources/1736047414721-6wbmj29s-5_mobb.png','resources/1735625225767-x4jr948t-img_05@2x.png','resources/1735625264674-t9g8592y-img_05@2x.png','resources/1734684510666-6c1hiehk-01.png','resources/1734684594020-5sw643i2-02.png','フロントエンドエンジニア','resources/1734756244010-cbpkc9ox-img_06.png','就活生のあなたへメッセージ','私も就活中、社会人になることに対して漠然とした不安を抱えていました。入社後も先輩社員の活躍を見て、「あんな立派に働く自分の姿が想像付かない」と更に不安が増したのを覚えています。\nしかし最初から完璧な人などいませんし、想像よりも社会は寛大です。先輩社員はみんな優しく支えてくれます。ペースは緩やかでも着実に成長していくものなので、みなさんも焦らず、身の丈よりちょっとだけ上の課題にどんどんチャレンジしてもらいたいなと思います。','2024-12-19 14:45:17','2025-01-17 08:36:21','web02',' Webデザイングループ'),(10,'H.N.','本社営業部','resources/1735620014340-o8z0sdmc-Group_14724.png','2021-01-01 00:00:00',3,'resources/1737102920458-mi0e5rn1-FV_06@2x.jpg','resources/1736047729346-sra8yuju-img_13.png','resources/1735625229563-vwij3s4s-img_06@2x.png','resources/1735625268488-aq762i91-img_06@2x.png','resources/1734684607069-3hfgd663-01.png','resources/1734684611115-hvgdf16b-02.png','営業','resources/1734757356693-zjr48l0o-img_06.png','就活生のあなたへメッセージ','学生時代は印刷会社と接する機会はあまり多くないかもしれません。私自身も、入社する前と後では印刷会社に対する印象が変わり、GAで対応できる機能のバリエーションの多さに驚きました。限りある学生生活の中で、自由に動ける今だからこそ、自分の目と足でいろんな会社に触れ合ってみてください！新しい発見に繋がり、将来の選択肢が広がっていくと思います。','2024-12-19 14:52:42','2025-01-17 08:35:43','sales02','本社営業'),(11,'Y.T.','東京市場開発部','resources/1735620011711-qumapvmo-2.png','2018-01-01 00:00:00',10,'resources/1737101962937-lhmqb6r2-FV_07@2x.jpg','resources/1736047559261-o5o45mn2-7_mobb.png','resources/1736760743974-sv5nryr0-be_img_07@2x.png','resources/1736760735538-l0s3v81k-af_img_07@2x.png','resources/1734684623336-62gy06ek-01.png','resources/1734684627494-xd25d8ev-02.png','Webディレクター','resources/1734757737598-ewg3tthq-img_06.png','就活生のあなたへメッセージ','どんな仕事に就くにしても、まずは「楽しそう」と感じることが大切かと思います。自分が興味を持ち、やりがいを感じられる仕事を見つけていただきたいです。\n初めて挑戦することばかりで、不安に感じることや困難に直面することもあるかもしれませんが、周囲のサポートを受けながら一歩一歩進んでもらえたらと思います。自分を信じて、前向きに挑戦し続けてください。応援しています 。','2024-12-19 14:58:01','2025-01-17 08:19:54','web01','Webデザイングループ');
/*!40000 ALTER TABLE `employees` ENABLE KEYS */;
UNLOCK TABLES;

