INSERT INTO `faqs` VALUES (18,'エントリー方法を教えてください。','エントリーは「マイナビ」から行っていただけます。メニュー右上にある「ENTRY」ボタンを押すと応募ページへ移動しますので、ぜひそちらからご応募ください。本サイトでは直接応募を受け付けておりませんので、ご了承ください。','募集要項について詳しくはこちら　','/recruitment','header1','2025-01-24 07:50:17','2025-01-24 07:53:09',0),(19,'選考から入社までの流れを教えてください。','選考は、エントリー▶︎会社説明会▶︎エントリーシート提出、適性検査▶︎1次面接（グループ）▶︎2次面接（個別）▶︎最終選考（グループ）▶︎内定、となります。入社までに懇親会や説明会が行われます。\n※採用プロセスやフローは、年度により変更の可能性があります。','募集要項について詳しくはこちら','/recruitment','header1','2025-01-24 07:51:27','2025-01-24 07:53:26',0),(20,'芸術・情報系の学部ではないのですが、 企画デザイン、Webデザイン、映像デザイン職の選考に影響はありますか？','いいえ、選考に影響はありません。芸術・情報系の学部や専門学校出身でない社員も多数働いています。未経験の場合でも、入社後の研修で業務に必要な知識はしっかり学ぶことができます。企画やものづくりが好きな方、またものづくりに熱い思いのある方はぜひご応募ください。c\n※ただし、上記のクリエイティブ職希望の場合は、面接時にポートフォリオや制作物の持参をお願いしています。趣味で作ったものでも構いませんので、ぜひお持ちください。','募集要項について詳しくはこちら','/recruitment','header1','2025-01-24 07:52:18','2025-01-24 07:53:40',0),(21,'面接は本当に私服で大丈夫なのでしょうか？','ぜひ、私服でお越しください。もちろんスーツでも構いませんが、面接では普段の自然な状態でお話しいただきたいと思っていますので、いつものリラックスした服装で来ていただけると嬉しいです。また、スーツを着ていても選考結果に影響はありませんので、ご安心ください。','募集要項について詳しくはこちら','/recruitment','header1','2025-01-24 07:54:20','2025-01-24 07:54:20',0),(22,'応募資格に年齢制限はありますか？既卒ですが応募可能でしょうか？','既卒でも応募可能です。現在、第二新卒まで募集しています。','募集要項について詳しくはこちら','/recruitment','header1','2025-01-24 07:54:54','2025-01-24 07:54:54',0),(23,'遠方に住んでいます。選考場所について教えてください。','適性試験、1次面接はオンラインで実施し、二次面接は、福岡・大阪・東京のいずれか最寄りの事業所、最終面接は福岡本社のみで行います。最終面接を受ける遠隔地の方は、規定に準じて交通費を支給します。','募集要項について詳しくはこちら','/recruitment','header1','2025-01-24 07:55:28','2025-01-24 07:55:28',0),(25,'制作会社は忙しそうなイメージですが、仕事とプライベートの両立はできますか？','部署や業務内容によって差はありますが、メリハリのある働き方をして仕事とプライベートを両立している社員が多い印象です。繁忙期などでどうしても残業する時期もありますが、その代わり仕事量の少ない日は早めに帰るなど、調整することもできます。また育児休暇や時短制度を活用し、子育てしながら活躍しているお父さん・お母さん社員も多数在籍しています。','データで見るGAについて詳しくはこちら','/data','header2','2025-01-24 07:56:11','2025-01-24 07:56:11',0),(26,'人材育成はどのように行なっていますか？','入社1年目は、仕事に必要な基礎知識やビジネススキルを学んだり、社内業務について理解を深めるために「他部門研修」を行っています。新人研修期間中は先輩社員がサポートとして付き添い、分からないことがあっても相談しやすい環境を整えていますので、どうぞご安心ください。また、部署単位でも定期的に勉強会や研修を行い、仕事に関する最新の知識や事例を学ぶことができます。','研修制度について詳しくはこちら','/environment/#anc02','header2','2025-01-24 07:56:59','2025-01-24 07:56:59',0),(27,'初任時、希望勤務地に配属してもらえますか？','はい、原則採用時に希望した地域での勤務となります。ただし入社後約1年間は本社のある福岡で研修を受け、その後希望勤務地へ配属となります。東京・関西といった遠隔地採用の方は、研修期間中、追加の家賃補助が出ます。また希望すれば借り上げ社宅に入ることもできます。また年に一度、部署異動の希望を出す機会があるため、希望が通れば別の地域で勤務することも可能です。','働く環境について詳しくはこちら','/environment','header2','2025-01-24 07:57:36','2025-01-24 07:57:36',0),(28,'若手でも自由に意見が言える環境ですか？','はい。部署や年齢、性別の垣根を超えて意見を言いやすい環境です。またやりたいことや挑戦したいことがあれば、若手の意見であってもきちんと話を聞いてもらえます。GA通信でも若手の声を発信しているので、ぜひこちらもご覧ください。','若手配信中！GA通信について詳しくはこちら（準備中）','#','header3','2025-01-24 07:58:14','2025-01-24 07:58:14',0),(29,'どんな社員が多いですか？','お客様の課題解決のために全力を尽くす社員が多いです。仕事に対して一生懸命な人が多いためか、個性豊かなメンバーが揃っています。','働き方インタビューについて詳しくはこちら','/interview','header3','2025-01-24 07:58:46','2025-01-24 07:58:46',0);
/*!40000 ALTER TABLE `faqs` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `media`
--

DROP TABLE IF EXISTS `media`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `media` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) DEFAULT NULL,
  `path` varchar(255) DEFAULT NULL,
  `caption` varchar(255) DEFAULT NULL,
  `description` varchar(255) DEFAULT NULL,
  `sizeInBytes` varchar(10) DEFAULT NULL,
  `mimeType` varchar(255) DEFAULT NULL,
  `mediaCategoryId` int DEFAULT NULL,
  `createdBy` int DEFAULT NULL,
  `updatedBy` int DEFAULT NULL,
  `isDeleted` varchar(255) DEFAULT '0',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `height` int DEFAULT NULL,
  `width` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `mediaCategoryId` (`mediaCategoryId`),
  KEY `createdBy` (`createdBy`),
  KEY `updatedBy` (`updatedBy`),
  CONSTRAINT `media_ibfk_1` FOREIGN KEY (`mediaCategoryId`) REFERENCES `media_categories` (`id`),
  CONSTRAINT `media_ibfk_2` FOREIGN KEY (`createdBy`) REFERENCES `users` (`id`),
  CONSTRAINT `media_ibfk_3` FOREIGN KEY (`updatedBy`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=448 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `media`
--

LOCK TABLES `media` WRITE;
/*!40000 ALTER TABLE `media` DISABLE KEYS */;
