/*!40000 ALTER TABLE `qna` DISABLE KEYS */;
INSERT INTO `qna` VALUES (1,5,1,'入社から現在までの遍歴や業務内容を教えてください。','私は大学で情報系を専攻していたため、当初はWeb系の職種で就職活動をしていました。しかし、GAの最終面接で「営業で挑戦してみないか？」とお声がけいただき、視野を広げられるまたとない機会と感じたため、営業職として入社しました。\n入社後の3ヶ月間は、設計部署で印刷技術や工程の基礎を徹底的に学び、その後営業チームへ配属され様々な営業のノウハウを学びました。2年目からは、複数のクライアントを担当し、見積の作成や印刷のスケジューリング、クライアントとの打ち合わせなど、幅広い業務を任されるようになりました。','resources/1735568118027-lb2o7un5-20230910_34157.png','2024-12-19 10:19:38','2025-01-14 08:53:58'),(2,5,3,'GA入社の決め手は何ですか？','印刷会社でありながら、時代の変化にあわせてWeb、映像といった新しい分野に積極的に取り組んでいる部分です。変化を恐れず、クライアントのニーズに応え、常に新しいことに挑戦されている姿勢に強く惹かれました。また、就職活動中は、様々な仕事に挑戦できる会社を探していたので、複数の事業分野に関われるGAの環境は、とても魅力的に感じました。','resources/1736434242154-jophuu6e-ace.png','2024-12-19 10:29:24','2025-01-14 08:55:37'),(3,5,5,'GAの企業理念である「分かりやすく伝わりやすく」を実現するために工夫していることはありますか？','打ち合わせでは、特定の人しか分からないような専門用語は避け、相手の理解度に応じた説明を心がけています。そうすることで言葉の行き違いを極力減らし、不明点などもすぐにその場で解決できるようにしています。また、紙の仕様などは電話やオンラインの打ち合わせではどうしても伝わりにくい部分があるため、打ち合わせはできるだけ対面で行うようにしています。\n提案書や見積の作成においては、グラフや図表を用いて視覚的に分かりやすい内容になるよう心がけています。','resources/1734602636929-taq62mzc-img_05.png','2024-12-19 13:05:49','2025-01-14 08:56:02'),(4,5,4,'GAに入ってやりがいを感じたことはなんですか？','自分が苦労して関わった印刷物が無事校了し、完成品を受け取った時です。\n社内で前例のない仕様のDMを作ることがあるのですが「実際に工場の機械で印刷できるかどうか」「郵便規定内で投函できるかどうか」などを、工場やデザイン部署の方々と相談したり、実際にサンプルを作って確認したりと、何度も試行錯誤を繰り返します。\n営業は商品設計から完成まで関わる分、大変なことも多いですが、自分の考えた仕様が実際に形になった時には、大きな達成感があります。','resources/1735568110929-vb6oiuyf-20230910_34064.png','2024-12-19 13:11:31','2025-01-14 08:55:50'),(5,6,1,'入社から現在までの遍歴や業務内容を教えてください。','1年目〜3年目は先輩にご指導いただきつつ、デザインの技術や印刷に適したデータの作り方等、毎日学ぶことだらけの連続でした。4年目から健康食品系の通販チラシをディレクションから担当することになったのですが、クライアントが伝えたい内容を整理したり、紙面上の構成を組み立てたりと、考えるべきことが広がり悪戦苦闘しました。今では担当クライアントと密にコミュニケーションを取り、疑問や相談事についてしっかりすり合わせを行い、良い信頼関係を築けています。','resources/1735575442419-lftovigi-20240808_33624.png','2024-12-19 13:20:48','2025-01-14 07:08:51'),(6,6,3,'GA入社の決め手は何ですか？','インターンに参加した際、会社や社員の方の雰囲気が伝わり、好印象を受けたからです。\n学生時代に学んだグラフィックデザインを活かしたいと思っていたので、グラフィック、Web、映像、3DCG等、幅広い分野の制作に取り組んでいる点も魅力に感じました。様々なデザインに携われることでデザイナーとしても成長できる環境だと思ったことも決め手の1つです。社内のパン工場でパンを作っているということも驚きました！パンが大好きなのでそこも魅力かもしれません。','resources/1735575451863-y8raf7tp-20240808_33681.png','2024-12-19 13:43:08','2025-01-14 07:11:07'),(7,7,1,'入社から現在までの遍歴や業務内容を教えてください。','私は現在入社2年目で、Webデザイナーとして働いています。仕事は主に製薬会社様や百貨店様向けのバナーやメルマガの制作を担当しています。\n実は、入社するまで本格的にデザインをしたことはなかったので、1年目の研修でIllustratorやPhotoshopの使い方を教わりながら、一からデザインやWebのことを勉強しました。現在は尊敬する先輩方の元で学びながら、日々仕事を頑張っています。最近は社内コンペに参加する機会も増え、少しずつ自分の成長を感じています。','resources/1736846013682-22lwpm21-img_01.jpg','2024-12-19 14:32:46','2025-01-14 09:14:02'),(8,7,3,'GA入社の決め手は何ですか？','元々デザイン系の仕事に興味があったのですが、大学は芸術系の学部ではなかったので、未経験でも挑戦できる会社を探していました。ちょうどその頃、学内の説明会でゼネラルアサヒを知り、デザイン未経験でも応募可能だったのと、説明会の雰囲気も和やかで居心地が良かったので入社を希望しました。また実際に同じ大学出身の先輩もいて、職場環境が楽しそうだったことや、何よりゼロからデザインを学べることが入社の決め手になりました。','resources/1735579162217-2o7p0phn-new_img_5_4.png','2024-12-19 14:33:32','2025-01-14 07:21:50'),(9,8,1,'入社から現在までの遍歴や業務内容を教えてください。','現在は映像チームで働いていますが、元々カメラマン志望で就職活動をしていました。\n1年目は希望通り撮影チームに配属されアシスタント業務を経験。2年目に映像チームへ異動し、スケジュールや予算の管理、撮影・編集の進行管理を担当しました。未経験の分野だったため、先輩方に一から業務内容を教えていただきました。\n3年目には関西事業部の映像チーム新設に伴い福岡から関西へ異動し、現在は映像ディレクターとして企画・演出・制作進行管理に携わっています。','resources/1735579570773-btfi26qj-240806_GAweb_recruit_3906_kitaura.png','2024-12-19 14:39:48','2025-01-14 07:49:59'),(10,8,3,'GA入社の決め手は何ですか？','就活中はカメラマンとして働ける会社を探していたので、自社内にスタジオを持っており大規模な撮影にも対応できるところに魅力を感じました。\nまた、GAは印刷、Web、スチール、映像など様々な媒体を扱っているため、いろんな知識を持ったプロたちと協力しながら働くことができます。私は写真を撮ることはもちろん、どういう写真を撮るかを企画することも好きだったので、いろんな立場の人と意見を交わしながらものづくりができる環境が自分の成長にも繋がると思い、入社を決めました。','resources/1735579579098-1mvp9sk9-240806_GAweb_recruit_3930_kitaura.png','2024-12-19 14:40:19','2025-01-14 08:36:21'),(11,9,1,'入社から現在までの遍歴や業務内容を教えてください。','私は関西Webチームに新卒社員として入社しました。大学では情報系を専攻していましたがWebは全くの未経験だったため、先輩エンジニアにご指導いただいたり、クライアントへの提案に同行したりしながらWeb制作の流れを学び、現在はフロントエンドエンジニアとして業務に励んでいます。\n普段の業務ではデザインをブラウザ上で閲覧できるようにコーディングしたり、ECサイトの解析業務などをしたりしています。','resources/1735579821822-mkhaikxh-new_5_img_1.png','2024-12-19 14:47:21','2025-01-14 08:39:15'),(13,10,1,'入社から現在までの遍歴や業務内容を教えてください。','健康食品と化粧品の通販会社様の営業をメインで担当しています。仕事内容は主に見積作成やデザイン制作のスケジュール管理です。\n紙媒体では、クライアントに向けてDM等の仕様提案を行なったり、制作物の構成やデザインをデザイナーとすり合わせ、クライアントとの窓口を担当しています。Web媒体では、Webディレクターと連携してECサイトの運営サポートをしたり、SNS投稿画像の撮影進行を行なったりしています。営業でありながらもクリエイティブな現場に関わる仕事をしています。','resources/1735580118312-uyd4raof-20230910_34214.png','2024-12-19 14:53:26','2025-01-14 08:43:20'),(14,10,3,'GA入社の決め手は何ですか？','就職活動中、私は印刷会社を中心に企業探しをしていました。多くの印刷会社では入社後にWeb媒体メインか紙媒体メイン、どちらの営業になるかを選ぶ必要がありましたが、GAはクライアントや自分の希望に応じて両方に携わることができるので他社よりも魅力を感じました。また、福岡県内の印刷会社の説明会に行った際に、何社かがGAを良い例として挙げられていたので、同業他社からも評価されているんだなと思い好印象を持ちました。','resources/1735580127551-6lh4w96m-20230910_34114.png','2024-12-19 14:53:52','2025-01-14 08:45:15'),(15,11,1,'入社から現在までの遍歴や業務内容を教えてください。','GAに新卒入社後Webチームに配属され、最初はコーディングを中心に業務を行っていました。未経験からのスタートでしたが、参考書で基礎を学び、周囲のサポートも受けながらスキルを磨いてきました。入社3年目には福岡から東京へ転勤し、それに伴い東京Webチームのリーダーに任命されました。現在はディレクション業務を中心にチーム全体のマネジメントにも取り組んでいます。日々困難に直面する場面もありますが、新たな知識やスキルを吸収しながら業務に取り組んでいます。','resources/1735580377749-ejosv720-_MG_7643.png','2024-12-19 14:59:00','2025-01-14 07:02:21'),(16,11,3,'GA入社の決め手は何ですか？','入社の決め手はシンプルに「楽しそう」と感じたことです。仕事の内容や社内の雰囲気が自分に合っていると感じました。また面接の選考を進んでいく中で、充実した研修制度や活躍する若手先輩社員の姿を実際に目にし、未経験からでもしっかりと成長できる環境だと確信しました。こうした楽しさと成長機会がある環境で、自分も貢献したいと強く思い入社を決意しました。','resources/1736851867295-p2mh5aef-in3.png','2024-12-19 14:59:38','2025-01-14 10:52:22'),(17,11,4,'GAに入ってやりがいを感じたことはなんですか？','入社してやりがいを感じたことは、未経験から始めたコーディング業務で成長を実感したことと、ディレクション業務で様々なプロジェクトを成功させたことです。特に、関わったプロジェクトが無事に完了し、クライアントから感謝の言葉をいただいた時には大きなやりがいを感じました。また、1つのプロジェクトを社内メンバーと協力し合いながら進め、共に成長していく過程も充実感があります。こうした経験を通じて、自分のスキル向上と、自分が貢献できる場が増えていくのを実感しています。','resources/1735580396876-fy64obvt-_MG_7617.png','2024-12-20 03:59:52','2025-01-14 07:05:55'),(19,11,5,'GAの企業理念である「分かりやすく伝わりやすく」を実現するために工夫していることはありますか？','企画や制作に取り組む際、まず初めに「受け取る人」の立場になることを意識しています。例えばスキンケア商材であれば、「どのような肌悩みを解決したいのか」「普段スキンケアにどれくらい時間を使うか」等を、使い手の目線に立って考えます。\nその上で、「どのような見せ方をすれば商品に興味を持ってもらえるか」「どのようなコンテンツがあれば長く続けてもらえるか」等、どのようにコミュニケーションを取るべきか考え、制作に落とし込むことが大切だと思っています。','resources/1734624625827-46yzx1o9-Group 12854.png','2024-12-20 05:11:04','2025-01-14 07:06:07'),(22,6,4,'GAに入ってやりがいを感じたことはなんですか？','自分がデザインした制作物が社内で印刷、加工、製本されて形になったものを見ると達成感を感じます。また、商品魅力を引き出す方法を試行錯誤し時間をかけて制作したチラシに対して、クライアントから「売上が上がった」「レスポンスが良かった」等の評価をいただけると自信に繋がります。頑張ってよかった〜！と思いますし、次の仕事へのモチベーションにも繋がっています。','resources/1735568159154-a51f3q0z-20240808_33584.png','2024-12-21 03:58:46','2025-01-14 07:11:22'),(23,7,4,'GAに入ってやりがいを感じたことはなんですか？','自分のデザインが実際にWebサイトに載っているのを見た時や、仕事のスピードが上がっていくのを実感した時です。特に、同僚や先輩方から評価された時や、クライアントから感謝の言葉をいただいた時は非常に嬉しいです。またデザインの仕事に就くことはずっと夢だったので、1つの案件が無事納品できた時の達成感は大きいですね。\nこれからもさらに多くの経験を積んで成長し、将来的には自分がやりたい仕事にも挑戦したいと思っています。','resources/1735579286942-qjx8lala-20240808_33225.png','2024-12-21 04:22:03','2024-12-30 17:21:41'),(24,8,4,'GAに入ってやりがいを感じたことはなんですか？','若手でも大きな仕事を任せてもらえることです。経験が浅かった当時は、分からないことや一筋縄で行かないことも多く「大変だな…」と思うこともありました。ですが、手探りながらも何とか納品した制作物をクライアントが気に入ってくださったり、担当案件が社外公開用の実績として選ばれたりすると「頑張った甲斐があったな」とやりがいを感じます。大変な分、1つ1つの仕事が確実に自分の実力になっていることを実感でき、モチベーションに繋がっています。','resources/1735579581144-ueib25pc-240806_GAweb_recruit_4040_kitaura.png','2024-12-21 04:33:51','2025-01-14 08:36:35'),(25,9,4,'GAに入ってやりがいを感じたことはなんですか？','サイト制作で試行錯誤している時にやりがいを感じます。\nフロントエンドエンジニアという職種ではありますが、ただコーディング業務を行うだけでなく、社内ミーティングやクライアントへの打ち合わせに参加することもあります。\n自分が制作した内容に対してクライアントからお喜びの声をいただけるのも大きなやりがいですが、ヒアリングした内容を噛み砕き、難解な要件を解決するためにどういった機能を組み合わせて実装するか、試行錯誤している時が一番楽しくやりがいを感じます。','resources/1735579831968-q7t8t8ik-new_img_5_5.png','2024-12-21 04:53:36','2025-01-14 08:40:46'),(26,10,4,'GAに入ってやりがいを感じたことはなんですか？','自分がクライアントに向けて提案した内容が採用され、新たな受注に繋がった時です。\nGAはクライアントから依頼された内容以外にも、さらに喜んでいただくために積極的に制作物の提案を行なっています。過去に取引のないクライアントに対しても自主提案を行う機会が多いです。\n自分で考え行動し、クリエイティブ職のみなさんと協力して形にしたものに対し、クライアントから「ありがとうございます」とお喜びの声をいただけた時に「もっと頑張ろう！」と思えます','resources/1735580127826-nshlvtga-20230910_34033.png','2024-12-21 05:06:28','2025-01-14 08:45:31'),(27,6,5,'GAの企業理念である「分かりやすく伝わりやすく」を実現するために工夫していることはありますか？','どんな人がこのチラシやDMを手に取るのか、この商品の魅力を引き出すにはどうすれば良いのか、クライアントが特に伝えたいポイントは何なのか、そして何より、どのような見せ方をすれば受け取り手に商品の魅力が伝わるのかなどを考えながらデザイン制作をしています。トライアンドエラーを繰り返し、良いものができた！と思えた時にやりがいを感じますし、素敵な仕事だな、と思います。','','2024-12-22 10:28:02','2025-01-14 07:11:36'),(28,7,5,'GAの企業理念である「分かりやすく伝わりやすく」を実現するために工夫していることはありますか？','分かりやすいデザインを作るためには、常に「自分がユーザーなら、どの動線で情報を見るか」を意識しています。デザインの基本ルールを守りつつ、様々なサイトから最新のトレンドやデザイン思考を学び、相手に伝わるデザインになるよう心がけています。\nまたスマホとパソコンでも同じ情報が伝わるよう、デザインが完成したら必ず自分のスマホで確認し、先輩にも見てもらっています。経験豊富な先輩方からのアドバイスを参考に、より分かりやすいサイトになるよう慎重に調整しています。','','2024-12-22 10:45:51','2024-12-22 10:45:51'),(29,8,5,'GAの企業理念である「分かりやすく伝わりやすく」を実現するために工夫していることはありますか？','本質を理解してこそ誰が見ても分かりやすく伝わりやすい視覚表現を生み出すことができるので、クライアントの事業内容や商材についてクライアントと同じ目線、立場で語れるくらいしっかりと理解することを心がけています。特に企画案やコンテを作成する時は、内容を体系的に理解してから行うようにしています。そうすることでクライアントの真意まで汲み取った「分かりやすく伝わりやすい」映像を実現できるからです。\nまた自分の意図をクライアントや社内スタッフに伝える際は、図や参考映像なども使用して共通のイメージを持てるようにしています。','','2024-12-22 11:51:46','2025-01-14 08:36:46'),(30,9,5,'GAの企業理念である「分かりやすく伝わりやすく」を実現するために工夫していることはありますか？','WebサイトやCMS(コンテンツ管理システム)を構築する際、常にエンドユーザーの行動を予測しながら作業をしています。取引先の伝えたい想いを制作物に落とし込むことはもちろんですが、エンドユーザーの行動心理に沿ったサイトを設計し、売り手からの一方的なコミュニケーションにならないよう心がけています。\nまた、どのような状況でも正しく分かりやすく情報が伝わり、適切なサービスを提供できるよう、ウェブアクセシビリティにも細心の注意を払って作業しています。','','2024-12-22 11:52:36','2025-01-14 08:41:01'),(31,10,5,'GAの企業理念である「分かりやすく伝わりやすく」を実現するために工夫していることはありますか？','社内外で何かを説明する際、口頭や文章で伝えるだけでなく、実物やそれに近しい制作物等をお見せしてイメージを共有できるようにしています。言葉だけだとお互いが共通のイメージを持てているかどうか把握しづらく、認識のズレが生じてしまう場合があります。クライアントが「思っていたものと違う」とならないためにも、実際のモノを見せた上でご説明するようにしています。','','2024-12-22 11:53:17','2025-01-14 08:45:42'),(32,9,3,'GA入社の決め手は何ですか？','Web業界で就職先を探していたところGAに出会いました。Web制作はもちろん、母体となる印刷事業に加え、映像や3DCGといったデジタルコンテンツにも力を入れており、事業内容の広さに企業としての幅と安心感を覚えました。\nまた、就活の選考中に面接を受けた際、取締役員と若手先輩社員の楽しげな笑い声が控室まで届いていました。面接中も終始和やかな雰囲気で、上下関係の隔たりのない風通しの良い職場だと感じたことも入社の決め手の一つです。','resources/1735579829848-5xp2b0f3-f.png','2024-12-30 17:31:53','2025-01-14 08:40:34');
