CREATE TABLE `role_actions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `requiredApproval` tinyint(1) DEFAULT '0',
  `isDeleted` tinyint(1) DEFAULT '0',
  `roleId` int NOT NULL,
  `roleMenuActionId` int DEFAULT NULL,
  `createdBy` int DEFAULT NULL,
  `editedBy` int DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `roleId` (`roleId`),
  KEY `roleMenuActionId` (`roleMenuActionId`),
  CONSTRAINT `role_actions_ibfk_1` FOREIGN KEY (`roleId`) REFERENCES `roles` (`id`),
  CONSTRAINT `role_actions_ibfk_2` FOREIGN KEY (`roleMenuActionId`) REFERENCES `role_menu_actions` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=659 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
