INSERT INTO `time_table` VALUES (164,1,'朝礼','その日の担当の人がお題に沿ったスピーチを行います。業務連絡もあれば一緒に行います。','08:30:00','2025-01-14 09:02:05','2025-01-14 09:02:05'),(165,1,'メール確認・見積・工程入力','クライアントよりいただいた依頼をもとに見積や印刷スケジュールなどデスクワークをメインに行います。','09:00:00','2025-01-14 09:02:05','2025-01-14 09:02:05'),(166,1,'昼休憩','社内に休憩スペースがあるので、そこで同期と一緒に弁当を食べています。','12:00:00','2025-01-14 09:02:05','2025-01-14 09:02:05'),(167,1,'打ち合わせ','デスクワークも行いますが、担当しているクライアント先に伺い、打ち合わせ等を行います。','13:00:00','2025-01-14 09:02:05','2025-01-14 09:02:05'),(168,1,'退社','筋トレやランニングを行い、体が鈍らないようにしています。','18:30:00','2025-01-14 09:02:05','2025-01-14 09:02:05'),(169,15,'朝礼・メール確認','チームで毎朝顔を合わせてタスクを確認し、メールの返信も行います。','09:00:00','2025-01-14 09:02:39','2025-01-14 09:02:39'),(170,15,'クライアントとの打ち合わせ','新規案件のオリエン参加や、提案などを行います。','10:00:00','2025-01-14 09:02:39','2025-01-14 09:02:39'),(171,15,'昼休憩','東京の事務所周辺には沢山のお店があります。','12:00:00','2025-01-14 09:02:39','2025-01-14 09:02:39'),(172,15,'デザイン・コーディングの内容確認','デザイナー、コーダーから上がってきたデータを確認し、必要があれば修正依頼を出します。','13:00:00','2025-01-14 09:02:39','2025-01-14 09:02:39'),(173,15,'社内MTG','新しい案件の確認や、次回提案までの内容・スケジュールをチェックします。','16:00:00','2025-01-14 09:02:39','2025-01-14 09:02:39'),(174,15,'退社','翌日のタスクやメールを確認して帰宅します。','19:00:00','2025-01-14 09:02:39','2025-01-14 09:02:39'),(175,14,'朝礼・メールとスケジュール確認','今日のタスクを確認し、一日の優先順位を決めます。','08:30:00','2025-01-14 09:02:53','2025-01-14 09:02:53'),(176,14,'入稿作業・設計と印刷確認','デザイナーが制作した印刷データを社内の担当部署に接続します。','09:00:00','2025-01-14 09:02:53','2025-01-14 09:02:53'),(177,14,'昼休憩','午前中から外部で打ち合わせがあった時は、そのまま外食することもあります。','12:00:00','2025-01-14 09:02:53','2025-01-14 09:02:53'),(178,14,'クライアントとの打ち合わせ・メールチェック・見積作成','クライアント先に伺い、打ち合わせをします。 夕方、会社に戻り次第メールを確認し、案件の見積やスケジュールを作成した後メールを送ります。','13:00:00','2025-01-14 09:02:53','2025-01-14 09:02:53'),(179,14,'退社','翌日のタスクを確認し帰宅します。','18:30:00','2025-01-14 09:02:53','2025-01-14 09:02:53'),(180,13,'朝礼・スケジュール確認','チームで負荷状況の確認をしつつ、スケジュールの遅れなどがないか確認します。','09:00:00','2025-01-14 09:03:05','2025-01-14 09:03:05'),(181,13,'クライアントとの打ち合わせ','オンラインショップの運用をサポートをさせていただいているクライアントと定例ミーティング。週1回のペースで行い、課題を確認します。','10:00:00','2025-01-14 09:03:05','2025-01-14 09:03:05'),(182,13,'昼休憩','早めにご飯を食べて、仮眠を取ったり、音楽を聴いたりしてリフレッシュします。','12:00:00','2025-01-14 09:03:05','2025-01-14 09:03:05'),(183,13,'コーディング作業','担当サイトのコーディングを進めます。ディレクターやデザイナーに要件をヒアリングしながら細部まで慎重に作業します。','13:00:00','2025-01-14 09:03:05','2025-01-14 09:03:05'),(184,13,'退社','翌日のタスクを確認して帰宅します。','18:30:00','2025-01-14 09:03:05','2025-01-14 09:03:05'),(185,12,'朝礼・メール確認','チームでの朝礼後、当日の作業を確認。その後メールの返信を行います。','09:00:00','2025-01-14 09:03:28','2025-01-14 09:03:28'),(186,12,'クライアントに提出する動画の確認','必要な作業が完了しているか確認し、修正がある場合は内容をまとめてエディターに伝えます。','10:00:00','2025-01-14 09:03:28','2025-01-14 09:03:28'),(187,12,'昼休憩','最近は自作したお弁当を持参しています。','12:00:00','2025-01-14 09:03:28','2025-01-14 09:03:28'),(188,12,'クライアントとの打ち合わせ','クライアントの希望をどのような表現、手法で映像に組み込んでいくかを考えながらヒアリングを行います。','13:00:00','2025-01-14 09:03:28','2025-01-14 09:03:28'),(189,12,'撮影香盤表の作成','撮影当日のスケジュールを作成します。5W1Hを意識しながら必要な情報を資料に落とし込みます。','16:30:00','2025-01-14 09:03:28','2025-01-14 09:03:28'),(190,12,'退社','担当案件のスケジュールを確認し帰宅。最近ミラーレス一眼を買ったので、家で写真の現像をするのがマイブームです。','19:00:00','2025-01-14 09:03:28','2025-01-14 09:03:28'),(196,10,'朝礼・メール確認','チームでのタスクの確認、朝のメール確認は必須です。','08:30:00','2025-01-14 09:03:54','2025-01-14 09:03:54'),(197,10,'デザイン修正','原稿を元にデザインの修正を行います。不明点がある場合はクライアントに連絡を取り確認を行います。','10:00:00','2025-01-14 09:03:54','2025-01-14 09:03:54'),(198,10,'昼休憩','パンを食べて、自席で仮眠を取ります。','12:00:00','2025-01-14 09:03:54','2025-01-14 09:03:54'),(199,10,'デザイン制作','企画書をもとに構成案や紙面の流れを考え、ラフを仕上げていきます。','13:00:00','2025-01-14 09:03:54','2025-01-14 09:03:54'),(200,10,'原稿整理','資料の整理も作業を効率的にするために大切です。','16:30:00','2025-01-14 09:03:54','2025-01-14 09:03:54'),(201,10,'退社','翌日のスケジュールを確認し帰宅します。急いで帰り愛猫と遊びます。','18:30:00','2025-01-14 09:03:54','2025-01-14 09:03:54'),(202,11,'朝礼・メール確認','チームメンバーに今日のタスクと終了予定時間を報告し、メール等を返信・チェックします。','09:00:00','2025-01-14 09:17:59','2025-01-14 09:17:59'),(203,11,'デザイン制作','期日までに仕上げるべく作業に集中します。','10:00:00','2025-01-14 09:17:59','2025-01-14 09:17:59'),(204,11,'昼休憩','前日に作った弁当を食べたり、新しいお店を探して気分転換しています。最近はデパ地下の健康弁当にハマっています。','12:00:00','2025-01-14 09:17:59','2025-01-14 09:17:59'),(205,11,'デザイン修正作業','先輩やディレクターからの修正指示を細かく確認しながら作業を進めます。MTGが入ることもあります。','13:00:00','2025-01-14 09:17:59','2025-01-14 09:17:59'),(206,11,'退社','その日の作業をまとめ、翌日の作業予想を報告し帰宅します。家ではハムスターとよく遊びます。','19:00:00','2025-01-14 09:17:59','2025-01-14 09:17:59');
